# Prompt: Using Python: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

import boto3
import os
import time
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from selenium.webdriver.common.by import By
from selenium.webdriver.support.ui import WebDriverWait
from selenium.webdriver.support import expected_conditions as EC
from PIL import Image
import io
from urllib.parse import urlparse

class ScreenshotService:
    def __init__(self):
        self.s3_client = boto3.client('s3')
        self.bucket_name = os.environ.get('S3_BUCKET_NAME', 'screenshots-bucket')
        self.setup_chrome_options()
        
    def setup_chrome_options(self):
        chrome_options = Options()
        chrome_options.add_argument('--headless')
        chrome_options.add_argument('--no-sandbox')
        chrome_options.add_argument('--disable-dev-shm-usage')
        chrome_options.add_argument('--window-size=1200,800')
        chrome_options.add_argument('--disable-gpu')
        chrome_options.add_argument('--remote-debugging-port=9222')
        self.chrome_options = chrome_options
        
    def validate_url(self, url):
        try:
            result = urlparse(url)
            return all([result.scheme, result.netloc])
        except:
            return False
            
    def take_screenshot(self, url, width=1200, height=800):
        if not self.validate_url(url):
            raise ValueError("Invalid URL")
            
        driver = webdriver.Chrome(options=self.chrome_options)
        try:
            driver.set_window_size(width, height)
            driver.get(url)
            
            # Wait for page to load
            WebDriverWait(driver, 10).until(
                EC.presence_of_element_located((By.TAG_NAME, "body"))
            )
            
            # Take screenshot
            screenshot = driver.get_screenshot_as_png()
            return screenshot
            
        finally:
            driver.quit()
            
    def resize_image(self, image_data, max_width=400, max_height=300):
        image = Image.open(io.BytesIO(image_data))
        image.thumbnail((max_width, max_height), Image.LANCZOS)
        
        output = io.BytesIO()
        image.save(output, format='JPEG', quality=85)
        return output.getvalue()
        
    def save_to_s3(self, image_data, key):
        self.s3_client.put_object(
            Bucket=self.bucket_name,
            Key=key,
            Body=image_data,
            ContentType='image/jpeg',
            Metadata={
                'created': str(int(time.time()))
            }
        )
        
    def get_screenshot_url(self, key):
        return f"https://{self.bucket_name}.s3.amazonaws.com/{key}"
        
    def process_url(self, url):
        try:
            # Take screenshot
            screenshot_data = self.take_screenshot(url)
            
            # Resize image
            resized_data = self.resize_image(screenshot_data)
            
            # Generate unique key
            url_hash = hash(url) % (10 ** 8)
            key = f"screenshots/{url_hash}.jpg"
            
            # Save to S3
            self.save_to_s3(resized_data, key)
            
            # Return URL
            return self.get_screenshot_url(key)
            
        except Exception as e:
            raise Exception(f"Failed to process URL: {str(e)}")

# AWS Lambda handler
def lambda_handler(event, context):
    service = ScreenshotService()
    
    try:
        url = event.get('url')
        if not url:
            return {
                'statusCode': 400,
                'body': 'URL parameter is required'
            }
            
        screenshot_url = service.process_url(url)
        
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': f'{{"url": "{screenshot_url}"}}'
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'body': f'{{"error": "{str(e)}"}}'
        }